import React, { useState, useEffect } from 'react';
import api from '../api/axios';

const ProductDetail = () => {
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  // State cho form
  const [id, setId] = useState('');
  const [name, setName] = useState('');
  const [price, setPrice] = useState(0);
  const [catID, setCatID] = useState('');
  const [image, setImage] = useState('');
  const [description, setDescription] = useState('');
  const [color, setColor] = useState('');
  const [memory, setMemory] = useState('');

  // 1. Lấy dữ liệu ban đầu
  useEffect(() => {
    apiGetProducts();
    apiGetCategories();
  }, []);

  const apiGetProducts = async () => {
    const res = await api.get('/products');
    setProducts(res.data);
  };
  const apiGetCategories = async () => {
    const res = await api.get('/categories');
    setCategories(res.data);
  };

  // 2. Xử lý Upload ảnh (Chuyển thành Base64)
  const previewImage = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (evt) => {
        setImage(evt.target.result); // Chuỗi base64
      };
      reader.readAsDataURL(file);
    }
  };

  // 3. Các hành động Thêm/Sửa/Xóa
  const btnAddClick = async (e) => {
    e.preventDefault();
    const newProd = { name, price, category: catID, image, description, color, memory };
    const res = await api.post('/products', newProd);
    if (res.data.success) { alert('Thêm thành công!'); apiGetProducts(); }
  };

  const btnUpdateClick = async (e) => {
    e.preventDefault();
    const newProd = { name, price, category: catID, image, description, color, memory };
    const res = await api.put('/products/' + id, newProd);
    if (res.data.success) { alert('Sửa thành công!'); apiGetProducts(); }
  };

  const btnDeleteClick = async (id) => {
    if (window.confirm('Chắc chắn xóa?')) {
      const res = await api.delete('/products/' + id);
      if (res.data.success) { alert('Xóa thành công!'); apiGetProducts(); }
    }
  };

  // Khi click vào dòng trong bảng thì đổ dữ liệu lên form
  const trClick = (item) => {
    setId(item._id); setName(item.name); setPrice(item.price); 
    setCatID(item.category?._id); setImage(item.image);
    setDescription(item.description); setColor(item.color); setMemory(item.memory);
  };

  return (
    <div>
      <div className="float-left">
        <h2 className="text-center">PRODUCT LIST</h2>
        <table className="datatable" border="1">
          <thead>
            <tr><th>ID</th><th>Name</th><th>Price</th><th>Category</th><th>Image</th><th>Action</th></tr>
          </thead>
          <tbody>
            {products.map((item) => (
              <tr key={item._id} onClick={() => trClick(item)}>
                <td>{item._id}</td>
                <td>{item.name}</td>
                <td>{item.price}</td>
                <td>{item.category?.name}</td>
                <td><img src={item.image} width="70px" height="70px" alt="" /></td>
                <td><button onClick={(e) => { e.stopPropagation(); btnDeleteClick(item._id); }}>Delete</button></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      
      <div className="float-right">
        <h2 className="text-center">PRODUCT DETAIL</h2>
        <form>
          ID: <input type="text" value={id} readOnly /><br/>
          Name: <input type="text" value={name} onChange={(e) => setName(e.target.value)} /><br/>
          Price: <input type="number" value={price} onChange={(e) => setPrice(e.target.value)} /><br/>
          Category: 
          <select value={catID} onChange={(e) => setCatID(e.target.value)}>
             <option value="">--Select--</option>
             {categories.map((c) => <option key={c._id} value={c._id}>{c.name}</option>)}
          </select><br/>
          Image: <input type="file" accept="image/*" onChange={previewImage} /><br/>
          Color: <input type="text" value={color} onChange={(e) => setColor(e.target.value)} /><br/>
          Memory: <input type="text" value={memory} onChange={(e) => setMemory(e.target.value)} /><br/>
          <button onClick={btnAddClick}>ADD NEW</button>
          <button onClick={btnUpdateClick}>UPDATE</button>
        </form>
      </div>
    </div>
  );
};
export default ProductDetail;
